import java.util.concurrent.*;
public class App {
    static void sleep(long ms) {
        try { Thread.sleep(ms); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
    }
    public static void main(String[] args) throws Exception {
        long start = System.currentTimeMillis();

        CompletableFuture<String> cfA = CompletableFuture.supplyAsync(() -> { sleep(200); return "Result-A"; });
        CompletableFuture<String> cfB = CompletableFuture.supplyAsync(() -> { sleep(100); return "Result-B"; });
        CompletableFuture<String> cfC = CompletableFuture.supplyAsync(() -> { sleep(300); return "Result-C"; });

        CompletableFuture.allOf(cfA, cfB, cfC)
            .thenRun(() -> {
                System.out.println("A: " + cfA.join());
                System.out.println("B: " + cfB.join());
                System.out.println("C: " + cfC.join());
                System.out.printf("Total time: ~%dms%n",
                    (System.currentTimeMillis() - start) / 100 * 100);
            })
            .get();
    }
}

