import java.util.concurrent.*;
public class App {
    static String safeResult(CompletableFuture<Integer> cf) throws Exception {
        return cf.handle((val, ex) -> {
            if (ex != null) return "FALLBACK (" + ex.getCause().getMessage() + ")";
            return "VALUE=" + val;
        }).get();
    }
    public static void main(String[] args) throws Exception {
        CompletableFuture<Integer> success = CompletableFuture.supplyAsync(() -> 42);
        CompletableFuture<Integer> failure = CompletableFuture.supplyAsync(() -> 10 / 0);

        System.out.println("Success handled: " + safeResult(success));
        System.out.println("Error handled: "   + safeResult(failure));
    }
}

