import java.util.*;
import java.util.concurrent.*;
import java.util.stream.*;
record Stock(String name, int price) {}
public class App {
    static void sleep(long ms) {
        try { Thread.sleep(ms); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
    }
    public static void main(String[] args) throws Exception {
        Map<String, Integer> prices = Map.of("TCS",3890,"RELIANCE",2450,"INFY",1560,"HDFC",1678,"WIPRO",412);

        List<CompletableFuture<Stock>> futures = prices.entrySet().stream()
            .map(e -> CompletableFuture.supplyAsync(() -> {
                sleep(50);
                return new Stock(e.getKey(), e.getValue());
            }))
            .collect(Collectors.toList());

        CompletableFuture.allOf(futures.toArray(new CompletableFuture[0]))
            .thenRun(() -> futures.stream()
                .map(CompletableFuture::join)
                .sorted((a, b) -> Integer.compare(b.price(), a.price()))
                .forEach(s -> System.out.printf("%s: ₹%d%n", s.name(), s.price())))
            .get();
    }
}

