import java.util.concurrent.*;
public class App {
    static void sleep(long ms) {
        try { Thread.sleep(ms); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
    }

    static CompletableFuture<String> validateCard(String cardId) {
        return CompletableFuture.supplyAsync(() -> {
            sleep(200);
            if (cardId.isEmpty()) throw new RuntimeException("Invalid card");
            return "Validated: " + cardId;
        });
    }
    static CompletableFuture<String> authorize(String validCard, int amount) {
        return CompletableFuture.supplyAsync(() -> {
            sleep(150);
            return "Authorized: ₹" + amount + " on " + validCard.replace("Validated: ", "");
        });
    }
    static CompletableFuture<String> updateLedger(String auth) {
        return CompletableFuture.supplyAsync(() -> {
            sleep(100);
            return "Ledger updated: TXN-001";
        });
    }

    public static void main(String[] args) throws Exception {
        System.out.println("Payment pipeline:");
        validateCard("card-4242")
            .thenCompose(validated -> {
                System.out.println("  " + validated);
                return authorize(validated, 1500);
            })
            .thenCompose(auth -> {
                System.out.println("  " + auth);
                return updateLedger(auth);
            })
            .thenAccept(ledger -> {
                System.out.println("  " + ledger);
                System.out.println("Payment successful!");
            })
            .exceptionally(ex -> {
                System.out.println("Payment FAILED: " + ex.getCause().getMessage());
                return null;
            })
            .get();
    }
}

