import java.util.concurrent.*;
import java.util.concurrent.atomic.*;
public class App {
    static AtomicInteger attempts = new AtomicInteger(0);

    static CompletableFuture<String> fetchWithRetry(int maxRetries) {
        return CompletableFuture.supplyAsync(() -> {
            int attempt = attempts.incrementAndGet();
            System.out.println("Attempt " + attempt + ": " + (attempt < 3 ? "failed" : "succeeded"));
            if (attempt < 3) throw new RuntimeException("transient error");
            return "Data on attempt " + attempt;
        }).exceptionally(ex -> {
            if (attempts.get() < maxRetries) return fetchWithRetry(maxRetries).join();
            throw new CompletionException(ex);
        });
    }

    public static void main(String[] args) throws Exception {
        String result = fetchWithRetry(3).get();
        System.out.println("Final result: " + result);
    }
}

