import java.util.concurrent.*;
public class App {
    static CompletableFuture<Integer> withLogging(String op, CompletableFuture<Integer> cf) {
        return cf.whenComplete((result, ex) -> {
            if (ex != null) System.out.println("[LOG] " + op + " failed: " + ex.getCause().getMessage());
            else            System.out.println("[LOG] " + op + " completed: result=" + result);
        });
    }
    public static void main(String[] args) throws Exception {
        CompletableFuture<Integer> add      = withLogging("add",      CompletableFuture.supplyAsync(() -> 10 + 5));
        CompletableFuture<Integer> divide   = withLogging("divide",   CompletableFuture.supplyAsync(() -> 10 / 0));
        CompletableFuture<Integer> multiply = withLogging("multiply", CompletableFuture.supplyAsync(() -> 6 * 7));

        // Collect results:
        CompletableFuture.allOf(add, divide.exceptionally(e -> -1), multiply).get();

        int addResult = add.join();
        int divResult = divide.exceptionally(e -> -1).join();
        int mulResult = multiply.join();
        System.out.printf("Final results: %d, %d (error), %d%n", addResult, divResult, mulResult);
    }
}

