import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;
import java.util.stream.*;
record Order(String id, int amount) {}
public class App {
    static ExecutorService pool = Executors.newFixedThreadPool(4);
    static ConcurrentHashMap<String, String> statuses = new ConcurrentHashMap<>();
    static AtomicInteger successful = new AtomicInteger(0);

    static void sleep(long ms) {
        try { Thread.sleep(ms); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
    }

    static CompletableFuture<String> processOrder(Order order) {
        return CompletableFuture.supplyAsync(() -> {
            sleep(50);
            if (order.amount() <= 0) throw new RuntimeException("invalid amount");
            return "VALIDATED";
        }, pool)
        .thenCompose(validated -> CompletableFuture.supplyAsync(() -> {
            sleep(80);
            return "PRICED ₹" + order.amount();
        }, pool))
        .thenCompose(priced -> CompletableFuture.supplyAsync(() -> {
            sleep(60);
            return "CONFIRMED ₹" + order.amount();
        }, pool))
        .whenComplete((result, ex) -> {
            if (ex != null) {
                statuses.put(order.id(), "FAILED");
            } else {
                statuses.put(order.id(), "CONFIRMED");
                successful.incrementAndGet();
            }
        })
        .exceptionally(ex -> "FAILED " + ex.getCause().getMessage());
    }

    public static void main(String[] args) throws Exception {
        List<Order> orders = List.of(
            new Order("ORD-001", 1500),
            new Order("ORD-002", -1),   // invalid — will fail
            new Order("ORD-003", 3000)
        );

        System.out.println("Processing " + orders.size() + " orders...");

        List<CompletableFuture<String>> futures = orders.stream()
            .map(App::processOrder)
            .collect(Collectors.toList());

        CompletableFuture.allOf(futures.toArray(new CompletableFuture[0]))
            .thenRun(() -> {
                for (int i = 0; i < orders.size(); i++) {
                    System.out.println(orders.get(i).id() + ": " + futures.get(i).join());
                }
                System.out.println("Successful: " + successful.get() + "/" + orders.size());
                System.out.println("Order statuses: " + new TreeMap<>(statuses));
            })
            .get();

        pool.shutdown();
    }
}
